	public boolean isEqual(Object obj) {
		if (obj instanceof Matrix) {
			Matrix m = (Matrix) obj;
			return isEqual(m);
		}
		return false;
	}

	public boolean isEqual(Matrix m) {
		if (m == null)
			return false;
		if (m.getRows()!= getRows() || m.getCols()!= getCols())
			return false;
		for (int i = 0; i < getRows(); i++) {
			for (int j = 0; j < getCols(); j++) {
				if (m.get(i, j)!= get(i, j))
					return false;
			}
		}
		return true;
	}

	public boolean isEqual(Matrix m, double tol) {
		if (m == null)
			return false;
		if (m.getRows()!= getRows() || m.getCols()!= getCols())
			return false;
		for (int i = 0; i < getRows(); i++) {
			for (int j = 0; j < getCols(); j++) {
				if (Math.abs(m.get(i, j) - get(i, j)) > tol)
					return false;
			}
		}
		return true;
	}

	public boolean isEqual(Matrix m, double tol, boolean strict) {
		if (m == null)
			return false;
		if (m.getRows()!= getRows() || m.getCols()!= getCols())
			return false;
		for (int i = 0; i < getRows(); i++) {
			for (int j = 0; j < getCols(); j++) {
				if (strict) {
					if (Math.abs(m.get(i, j) - get(i, j)) > tol)
						return false;
				} else {
					if (Math.abs(m.get(i, j) - get(i, j)) > tol)
						return false;
				}
			}
		}
		return true;
	}

