	public void add( T item ) {
		if( item == null ) return;

		if( size == items.length ) {
			T[] newItems = (T[]) Array.newInstance( item.getClass(), items.length * 2 );

			System.arraycopy( items, 0, newItems, 0, items.length );

			items = newItems;
		}

		items[ size++ ] = item;
	}

	public void remove( T item ) {
		if( item == null ) return;

		for( int i = 0; i < size; i++ ) {
			if( items[ i ] == item ) {
				items[ i ] = items[ --size ];
				items[ size ] = null;

				return;
			}
		}
	}

	public void clear() {
		for( int i = 0; i < size; i++ ) {
			items[ i ] = null;
		}

		size = 0;
	}

	public int size() {
		return size;
	}

	public T[] items() {
		return items;
	}
}
