package com.myJava.file.delta.tools;

import java.io.IOException;
import java.io.InputStream;
import java.io.OutputStream;

public class IOHelper {
    public static void readFully(InputStream in, byte[] b) throws IOException {
        readFully(in, b, 0, b.length);
    }

    public static void readFully(InputStream in, byte[] b, int off, int len) throws IOException {
        int read = 0;
        while (read < len) {
            int r = in.read(b, off + read, len - read);
            if (r == -1) {
                throw new IOException("EOF");
            }
            read += r;
        }
    }

    public static void writeFully(OutputStream out, byte[] b) throws IOException {
        writeFully(out, b, 0, b.length);
    }

    public static void writeFully(OutputStream out, byte[] b, int off, int len) throws IOException {
        int written = 0;
        while (written < len) {
            int w = out.write(b, off + written, len - written);
            if (w == -1) {
                throw new IOException("EOF");
            }
            written += w;
        }
    }

    public static int get32(byte[] b, int off) {
        return (b[off] & 0xFF) | ((b[off + 1] & 0xFF) << 8) | ((b[off + 2] & 0xFF) << 1

